import { isNullOrUndefinedOrEmpty } from '../validation/null-checks.js'

/**
 * Formatea un valor como moneda CLP (Peso Chileno)
 * @param {number} value
 * @returns {string}
 */
export const formatoMoneda = (value) => {
  if (isNullOrUndefinedOrEmpty(value)) return ''
  return value.toLocaleString('es-CL', { style: 'currency', currency: 'CLP' })
}

/**
 * Formatea un valor como moneda USD
 * @param {number} value
 * @returns {string}
 */
export const formatoInternacional = (value) => {
  if (isNullOrUndefinedOrEmpty(value)) return ''
  return value.toLocaleString('en-EN', { style: 'currency', currency: 'USD' })
}
